    class_attributes,
    enrollment_requirements
) VALUES
    ('AAAD-A 100', 'AFRICAN AMERICAN DANCE COMPANY: FOUNDATIONS AND PRACTICES', '7878', 'Class Status', 'TuTh Tuesday, Thursday 4:20 PM–7:20 PM', 'TH A217', 'Stafford Berry', 12, NULL, 'Lecture', '2', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Emphasis on ethnic and jazz traditions although other genres are regularly preformed. Repertoire varies from semester to semester. Participation in on and off-campus concerts, workshops, and lecture demonstrations required.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 110', 'AFRICAN AMERICAN CHORAL ENSEMBLE: FOUNDATIONS AND PRACTICES', '3217', 'Class Status', 'MW Monday, Wednesday 3:10 PM–4:40 PM', 'HD TBA TH A219 TH A111', 'Raymond Wise', 19, NULL, 'Lecture', '2', 'BLDG NOT ASSIGNED, LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'The ensemble performs music composed by, for and about blacks, including spirituals, gospel, art songs, and excerpts from operas and musicals. Repertoire varies from semester to semester. Participation in on- and off-campus concerts, workshops, and lecture demonstrations required. No audition required. Students meet the first day of class prepared to sing. Vocal evaluations and part assignments will be done during class. Ability to read music is desirable but not essential.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 112', 'BLACK MUSIC OF TWO WORLDS', '30198', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'AC C116', 'Olivia Ekeh', 0, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'An exploration of the relationships among musics of West and Central African people and their descendents in the United States, Latin America, and the Caribbean. Emphasis placed on the conceptual and aesthetic continuities between musical expression in Old and New World contexts-a uniformity which exists because of shared African cultural ancestry.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AAAD-A 113', 'ATKINS LIVING-LEARNING CENTER FOUNDATIONAL COURSE', '7184', 'Closed', 'M Monday 6:40 PM–7:30 PM', 'FR C230', 'Latonya Wilson', 0, NULL, 'Lecture', '1', 'FOREST QUAD', ARRAY[]::TEXT[], 'Examines the impact of African American history and culture on the nation as a whole and on the international community.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 120', 'SOUL REVUE: FOUNDATIONS AND PRACTICES', '3218', 'Class Status', 'TuTh Tuesday, Thursday 4:20 PM–6:20 PM', 'TH A111', 'James Strong', 25, NULL, 'Lecture', '2', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Introduces the richness and depth of black popular tradition through authentic performance practices. Repertoire varies from semester to semester. Participation in on- and off-campus concerts, workshops, and lecture demonstrations required. Ability to read music desirable but not essential.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 150', 'SURVEY OF THE CULTURE OF BLACK AMERICANS', '13589', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'LH 035', 'George Ike', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Explores the culture of Blacks in America viewed from a broad interdisciplinary approach, employing resources from history, literature, folklore, religion, sociology, and political science.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
