    ('AAAD-A 156', 'BLACK LIBERATION STRUGGLES AGAINST JIM CROW AND APARTHEID', '8494', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WI C109', 'Marshall Allen', 0, NULL, 'Lecture', '3', 'WILLKIE C', ARRAY[]::TEXT[], 'A comparative perspective on American race-relations, specifically the similarities and differences in the struggles against Jim Crow in America and against apartheid in South Africa. In both places, the late twentieth century witnessed a revolt against the legal and philosophical framework of white supremacy.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AAAD-A 203', 'STUDYING BLACKS OF THE NEW WORLD: AFRICAN AMERICANS AND AFRICANS IN THE AFRICAN DIASPORA', '37441', 'Class Status', 'MW Monday, Wednesday 10:25 AM–12:55 PM', 'KH 016', 'Nana Amoah-Ramey', 15, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'A comparative study of the cultural, historical and socio-economic life patterns of African Americans and diaspora based Africans in the United States.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AAAD-A 205', 'BLACK ELECTORAL POLITICS', '30199', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PY 111', 'Randal Jelks', 3, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'The course will explore black participation in the formal structures of American government and in the processes by which these structures are accessed. Black participation in local, state and federal government arenas will be focused upon and the political benefits to the black community of these involvements will be assessed.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('AAAD-A 210', 'BLACK WOMEN IN THE DIASPORA', '13592', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WI C109', 'Candis Smith', 3, NULL, 'Lecture', '3', 'WILLKIE C', ARRAY[]::TEXT[], 'Interdisciplinary examination of salient aspects of black women''s history, identity, and experience, including policies, cultural assumptions, and knowledge systems that affect black women''s lives. While the primary focus will be North America, the lives of black women in other cultural settings within the African Diaspora will also be examined.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('AAAD-A 221', 'DANCE IN THE AFRICAN DIASPORA', '30202', 'Class Status', 'TuTh Tuesday, Thursday 11:55 AM–2:25 PM', 'TH A217', 'Stafford Berry', 3, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Introduction to the history, culture, music, and body movements of dances in the African American and African Diaspora tradition with a focus on African-derived dances, primarily from Cuba, Puerto Rico, and America. Instruction through classroom lectures, discussions, videos, readings, and movement sessions.', ARRAY['IUB GenEd World Culture credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AAAD-A 263', 'CONTEMPORARY SOCIAL ISSUES IN THE AFRICAN AMERICAN COMMUNITY', '37312', 'Class Status', 'MW Monday, Wednesday 11:35 AM–2:05 PM', 'SY 106', 'Carolyn Calloway-Thomas', 13, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'A seminar, primarily designed for sophomores and juniors, directed to critical analysis of selected topics germane to future socio-economic and political position of Afro-Americans.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
