    ('AAAD-A 295', 'SURVEY OF HIP HOP', '5403', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WB WEB', 'Fernando Orejuela', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examines rap music and hip hop culture as artistic and socio-cultural phenomena with emphasis on historical, cultural, economic, and political contexts. Topics include the coexistence of various hip hop styles, their appropriation by the music industry, and controversies resulting from the exploitation of hip hop as a commodity for national and global consumption.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('AAAD-A 337', 'SOUL REVUE: ADVANCED STUDIES AND PRACTICES', '7185', 'Class Status', 'TuTh Tuesday, Thursday 4:20 PM–6:20 PM', 'TH A111', 'James Strong', 25, NULL, 'Lecture', '2', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Focuses on music industry concerns related to the ensemble''s live presentations of Black popular music. Explores how Black popular music is manifested within the broader context of the music industry. Readings explore music industry structures and practices (copyright law, publishing, creative production, etc.) that directly impact African American artists'' creative output and livelihood.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 338', 'AFRICAN AMERICAN DANCE COMPANY: ADVANCED STUDIES AND PRACTICES', '7879', 'Class Status', 'TuTh Tuesday, Thursday 4:20 PM–7:20 PM', 'TH A217', 'Stafford Berry', 6, NULL, 'Lecture', '2', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Students learn dance technique and experience performance from the perspective of the African American and African diaspora. Students perform in choreographic works created by the director and in works produced from student collaborative projects.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 339', 'AFRICAN AMERICAN CHORAL ENSEMBLE: ADVANCED STUDIES AND PRACTICES', '7186', 'Class Status', 'MW Monday, Wednesday 3:10 PM–4:40 PM', 'HD TBA TH A219 TH A111', 'Raymond Wise', 19, NULL, 'Lecture', '2', 'BLDG NOT ASSIGNED, LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Continues choral ensemble participation and the goals of A110. Through meetings with the instructor, students may complete a research project, and develop advanced-level choral leadership skills in vocal techniques, advanced sight reading, and intermediate piano skills. Students will organize and perform in small ensembles to demonstrate their abilities to perform Black choral music.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 355', 'AFRICAN-AMERICAN HISTORY I', '13068', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'WH 106', 'Randal Jelks', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], NULL, ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('AAAD-A 379', 'EARLY BLACK AMERICAN WRITING', '34487', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SY 001', 'Maria Hamilton Abegunde', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], NULL, ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('AAAD-A 386', 'BLACK FEMINIST PERSPECTIVES', '30212', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WH 104', 'Elena Guzman', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Examination of the history, development, and manifestation of feminist consciousness among African American women. The course is particularly concerned with how black women''s lived experience defines that consciousness, and the differing impact it has among various groups of black women, and in their larger social, political, cultural communities.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('AAAD-A 387', 'BLACK MIGRATION', '6894', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'TV 226', 'Candis Smith', 18, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Explores the process, patterns, and paradoxes of the incorporation of individuals and groups identified and/or perceived as "immigrants" from a comparative-interdisciplinary perspective. Focuses on persons from "sending" countries in Africa, the Caribbean, and Asia to the United States, and also examines developments in other labor-importing, post-industrial countries such as France and England in relation to the people who settle there.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AAAD-A 398', 'ADVANCED TOPICS IN SOCIAL AND HISTORICAL STUDIES FOR AAADS', '30208', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WH 104', 'Olivia Ekeh', 15, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Advanced study with analysis of selected issues and problems within the African American and African Diaspora experience utilizing interdisciplinary interpretation through analytical reasoning and philosophical discussions. Varied topics primarily in the areas of history, politics, sociology, anthropology, and economics.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('AAAD-A 398', 'ADVANCED TOPICS IN SOCIAL AND HISTORICAL STUDIES FOR AAADS', '37316', 'Class Status', 'TuTh Tuesday, Thursday 1:55 PM–4:25 PM', 'BH 647', 'Valerie Grim', 9, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Advanced study with analysis of selected issues and problems within the African American and African Diaspora experience utilizing interdisciplinary interpretation through analytical reasoning and philosophical discussions. Varied topics primarily in the areas of history, politics, sociology, anthropology, and economics.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('AAAD-A 398', 'ADVANCED TOPICS IN SOCIAL AND HISTORICAL STUDIES FOR AAADS', '14354', 'Closed', NULL, 'WB WEB', 'Candis Smith', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Advanced study with analysis of selected issues and problems within the African American and African Diaspora experience utilizing interdisciplinary interpretation through analytical reasoning and philosophical discussions. Varied topics primarily in the areas of history, politics, sociology, anthropology, and economics.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('AAAD-A 420', 'TRANSFORMING DIVIDED COMMUNITIES AND SOCIETIES', '30210', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SY 103', 'Carolyn Calloway-Thomas', 12, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Investigation of divided societies and of strategies for transforming such communities. Students will consider societies (both past and present) divided by race, ethnicity, gender, class, caste, tribe, or religion, and will study responses such as civil rights, affirmative action, reparation policies, and reconciliation tribunals.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('AAAD-A 479', 'CONTEMPORARY BLACK POETRY', '10786', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WH 109', 'Maria Hamilton Abegunde', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], NULL, ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('AAAD-A 481', 'RACISM AND THE LAW', '30211', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 144', 'Frank Motley', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Contemporary racial problems in American Society with regard to law and constitutional principles of basic freedoms and associated conflicts. Effects of societal norms and impact of racism.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('AAAD-A 493', 'SENIOR SEMINAR IN AFRICAN AMERICAN AND AFRICAN DIASPORA STUDIES', '3219', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 333', 'Valerie Grim', 15, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Lecture/discussions on Afro-American studies as an interdisciplinary field of inquiry and scholarship. Students will develop individual or group projects that synthesize their experiences as majors by demonstrating the interrelatedness of the department''s concentration areas.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 499', 'HONORS THESIS', '3220', 'Class Status', NULL, NULL, 'Jakobi Williams', 3, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'Development, completion, and defense of Honors thesis.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 500', 'INTR AFRC AM&AFRC DIASP PART I', '30214', 'Class Status', 'W Wednesday 2:20 PM–4:50 PM', 'BH 647', 'Valerie Grim', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Through an interdisciplinary approach, students are introduced to the major works concerning the historical, cultural, and intellectual experiences of Africans in the Diaspora, and the research, methodology, and theoretical questions raised therein in preparation for study in Afro-American studies.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 555', 'CARIB/AFRO-AMER/AFRI LEADRSHP', '30215', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 312', 'Nana Amoah-Ramey', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Course will deal with aspects of Caribbean, African-American, and African leadership that influenced the struggles for decolonization and civil rights in the Caribbean, United States, and Africa. The course will also discuss how leaders of the three areas were much more interested in political freedom than economic emancipation.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 599', 'MA THESIS RESEARCH', '5381', 'Class Status', NULL, NULL, 'Jakobi Williams', 5, NULL, 'Research', '1–6', NULL, ARRAY[]::TEXT[], 'Students who are have completed their MA coursework should take this course to work on their thesis research. These credits are intended to give the student credit for work done on the thesis.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 620', 'TRANSFORMING DIVIDED COMMUNITIES AND SOCIETIES', '30216', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SY 103', 'Carolyn Calloway-Thomas', 5, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Investigation of divided societies and of strategies for transforming such communities. Students will consider societies (both past and present) divided by race, ethnicity, gender, class, caste, tribe, or religion, and will study responses such as civil rights, affirmative action, reparation policies, and reconciliation tribunals.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 669', 'INDEP PROJ BLACK SOCIAL ISSUES', '3221', 'Class Status', NULL, NULL, 'Jakobi Williams', 5, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'This course is designed to meet individual interests of students by providing opportunities for research on a chosen topic and by encouraging non-traditional approaches or settings in the application of concepts developed in formal classes.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 679', 'CONTEMPORARY BLACK POETRY', '11158', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WH 109', 'Maria Hamilton Abegunde', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'An examination of Black poetry from Dunbar to the present, emphasizing the emergence, growth, and development of Black consciousness as a positive ethnic identification.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 686', 'GRAD INTERNSHIP AFRO-AMER STDS', '3222', 'Class Status', NULL, NULL, 'Jakobi Williams', 3, NULL, 'Internship', '4', NULL, ARRAY[]::TEXT[], 'Directed readings, work experience, journal, oral presentation. Most research experiences will require research skills.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 689', 'INDEP. PROG. IN BLK LITERATURE', '3223', 'Class Status', NULL, NULL, 'Jakobi Williams', 4, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'This course is designed to meet individual interests of students by providing opportunities for research on a chosen topic and by encouraging non-traditional approaches or settings in the application of concepts developed in formal classes.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 698', 'FIELD STUDY SEMINAR', '3224', 'Class Status', NULL, NULL, 'Jakobi Williams', 4, NULL, 'Independent Study', '4', NULL, ARRAY[]::TEXT[], 'This course is for the development of the final master''s project. A critical paper, a thesis-length documentation of a field study, or a substantial record of creative activity are required.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 699', 'INDPT PROJECT IN BLACK MUS', '13053', 'Class Status', NULL, NULL, 'Jakobi Williams', 1, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'This course is designed to meet individual interests of students by providing opportunities for research on a chosen topic and by encouraging non-traditional approaches or settings in the application of concepts developed in formal class settings.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 699', 'INDPT PROJECT IN BLACK MUS', '3225', 'Class Status', NULL, NULL, 'Jakobi Williams', 4, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'This course is designed to meet individual interests of students by providing opportunities for research on a chosen topic and by encouraging non-traditional approaches or settings in the application of concepts developed in formal class settings.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 799', 'STUDY AND RESEARCH ABROAD IN AAADS', '5286', 'Class Status', NULL, NULL, 'Jakobi Williams', 4, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'This course is designed to introduce students to different peoples, cultures, histories, literary works, political systems and others by having them spend time in Diasporic communities concerning peoples of African descent.', ARRAY[]::TEXT[], NULL),
    ('AAAD-A 899', 'AAADS PHD DISSERTATION RESEARCH', '5239', 'Class Status', NULL, NULL, 'Jakobi Williams', 5, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], 'Students who are candidates should take this course to work on their dissertation research. These credits are intended to give the student credit for work done on the dissertation.', ARRAY[]::TEXT[], NULL),
    ('AAAD-G 599', 'THESIS RESEARCH', '4716', 'Class Status', NULL, NULL, 'Jakobi Williams', 5, NULL, 'Lecture', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('AAAD-G 901', 'ADVANCED RESEARCH', '5240', 'Class Status', NULL, NULL, 'Jakobi Williams', 5, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('AAAD-X 373', 'INTERNSHIP IN AFRICAN AMERICAN AND AFRICAN DIASPORA STUDIES', '6052', 'Class Status', NULL, NULL, 'Jakobi Williams', 3, NULL, 'Internship', '3', NULL, ARRAY[]::TEXT[], 'Directed readings, field research, research papers. Certain internship experiences may require research skills.', ARRAY[]::TEXT[], NULL),
