    ('AAAD-X 490', 'INDIVIDUAL READINGS IN AFRICAN AMERICAN STUDIES', '7208', 'Class Status', NULL, NULL, 'Jakobi Williams', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
