    ('AAAD-X 490', 'INDIVIDUAL READINGS IN AFRICAN AMERICAN STUDIES', '7210', 'Class Status', NULL, NULL, 'Jakobi Williams', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AAAD-X 490', 'INDIVIDUAL READINGS IN AFRICAN AMERICAN STUDIES', '7211', 'Class Status', NULL, NULL, 'Jakobi Williams', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AAAD-X 490', 'INDIVIDUAL READINGS IN AFRICAN AMERICAN STUDIES', '7212', 'Class Status', NULL, NULL, 'Jakobi Williams', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AAAD-X 490', 'INDIVIDUAL READINGS IN AFRICAN AMERICAN STUDIES', '7504', 'Class Status', NULL, NULL, 'Jakobi Williams', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AADM-Y 500', 'TOPICS IN ARTS ADMINISTRATION', '8605', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HD TBA', 'Adrian Starnes', 1, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Selected research and discussion topics organized on a semester by semester basis.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 502', 'INTRODUCTION TO ARTS ADMINSTRATION AND ORGANIZATIONAL BEHAVIOR', '6441', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'I 107', 'Julia Dessauer', 8, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course introduces graduate students to the professional world of arts administration, its many disciplines, its dramatically and rapidly changing landscape, and the nature and culture of its organizations. Major concepts of organizational behavior by employees, administrators, and organizations themselves will be discussed.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 506', 'CURATING IN GALLERIES AND MUSEUMS', '10208', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WH 008', 'Sarah Hatcher', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course explores the idea and practice of curating, from displaying a single object to organizing a complex exhibition. Course provides a body of knowledge and helps students develop skills to curate and evaluate the role of curation and display of objects - all essential to museum and gallery management.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 511', 'PERFORMING ARTS CENTER MANAGEMENT', '32096', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'TV 245', 'Doug Booher', 10, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on the business and legal aspects of contracting to present live performances and managing a performing arts facility. Including: the process of contracting and marketing a performance series; the issues involved with operating a performing arts center facility; the marketing forces at work in the live performance industry; the legal and ethical issues involved in the industry. Will provide students with a balance between academic and real world issues.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 515', 'FINANCIAL MANAGEMENT FOR THE ARTS', '11837', 'Class Status', 'M Monday 2:20 PM–5:10 PM', 'PV A203', 'JL Nave', 10, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The course introduces students to the role of financial management in the modern not-for-profit organization. This course covers applications of budgeting, financial and managerial accounting principles, and procedures and financial analysis for non-profit organizations. Materials covered should be considered required knowledge for the mid-to senior-level arts administrator.', ARRAY['Class uses IU eTexts'], NULL),
    ('AADM-Y 550', 'PRACTICUM IN ARTS ADMINISTRATION', '1002', 'Class Status', 'F Friday 9:00 AM–1:00 PM', 'PV 278', 'Megan Starnes', 30, NULL, 'Independent Study', '0–3', 'SPEA', ARRAY[]::TEXT[], 'The practicum focuses on building your professional portfolio by adding variety and depth to your arts administration skill set through self-directed projects, research, and/or participation in shadowing, conferences, and workshops. Students complete a total of 150 hours (3 credits) of practicum over the course of their time in the program.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 550', 'PRACTICUM IN ARTS ADMINISTRATION', '8486', 'Class Status', NULL, NULL, 'Megan Starnes', 36, NULL, 'Independent Study', '0–3', 'SPEA', ARRAY[]::TEXT[], 'The practicum focuses on building your professional portfolio by adding variety and depth to your arts administration skill set through self-directed projects, research, and/or participation in shadowing, conferences, and workshops. Students complete a total of 150 hours (3 credits) of practicum over the course of their time in the program.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 559', 'PUBLIC POLICY AND THE ARTS', '32107', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 275', 'Ursula Kuhar', 33, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course looks at the various philosophies and practices of government support for the arts in the US and elsewhere. Additional selected topics include ethical issues regarding problematic works of art, multiculturalism and diversity, equity in the arts, and the politicization of art.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 562', 'LEGAL ISSUES IN THE ARTS', '8487', 'Class Status', 'Tu Tuesday 8:00 AM–10:30 AM', 'AC C114', 'Robert Wylie', 8, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course considers national and international legal aspects of the protection of cultural heritage and cultural diversity, copyright and related rights, freedom of expression, antitrust, and the evolving legal frameworks regulating social media.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 650', 'SEMINAR IN ARTS ADMINISTRATION', '1003', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV A205', 'Karen Gahl-Mills', 5, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Seminar that addresses key leadership and management issues for arts administrators: organizational culture and teamwork, healthy conflict, trust and accountability, boards and governance, change and crisis management, personal leadership development. Course is structured to include lecture/discussion, reflection, simulations, and visits by guest speakers.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 680', 'READINGS IN ARTS ADMINISTRATION', '1004', 'Class Status', NULL, NULL, 'Karen Gahl-Mills', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised readings in Arts Administration.', ARRAY[]::TEXT[], NULL),
    ('AADM-Y 690', 'INDEPENDENT STUDY IN ARTS ADMINISTRATION', '1005', 'Class Status', NULL, NULL, 'Karen Gahl-Mills', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AADM-Y 750', 'INTERNSHIP IN ARTS ADMINISTRATION', '1006', 'Class Status', NULL, NULL, 'Celeste Ross', 144, NULL, 'Independent Study', '0–3', NULL, ARRAY[]::TEXT[], 'The internship shall consist of 280 hours, in a managerial office of a museum, theatrical or musical organization, or community, state, regional, or national arts council. Taken in the summer following the first year of course work or in the spring or summer following the final semester of course work.', ARRAY[]::TEXT[], NULL),
    ('AAST-A 101', 'INTRODUCTION TO ASIAN AMERICAN STUDIES', '30421', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'WY 101', 'Lisa Kwong', 0, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Examines the histories, experiences, and cultures that shape the Asian American community. Through articles, books, and film, this course explores the commonalities and the diversity of experiences among Asians in the United States, with particular focus on such issues as immigration, education, community, and identity.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('AAST-A 201', 'ASIAN DIASPORA EXPERIENCE', '10433', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'AC C002', 'Lisa Kwong', 0, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Explores the Asian Diaspora in the United States and elsewhere in the world. Examines Asian diasporic experience through diverse cultural forms: literature, art, music, dance, theater, news, film, and other popular media. Addresses such salient issues as identity in transition, ecology and human ecology, globalization, and more.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('ABEH-A 101', 'INTRODUCTION TO ANIMAL BEHAVIOR', '12316', 'Closed', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'GY 1045', 'Lisa Barrett', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Provides students with a general introduction to the scientific study of animal behavior, including a broad overview of how developmental, physiological, and ecological factors determine behaviors and the evolutionary forces that shape those behaviors.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('ABEH-A 200', 'WORKSHOP IN ANIMAL BEHAVIOR', '8024', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 008', 'Lisa Barrett', 2, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'For students pursuing a major in animal behavior. Introduces a range of research topics within animal behavior. Provides information on general experimental methods and design and on potential research opportunities in the field.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('ABEH-A 301', 'ANIMAL CONSERVATION SCIENCE', '14064', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 227', 'Adam Fudickar', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Following an introduction to the broad field of conservation biology, students learn how research in ecology, evolution, behavior, physiology, genetics, genomics, and development are applied to animal conservation.', ARRAY[]::TEXT[], NULL),
    ('ABEH-A 350', 'ANIMAL BEHAVIOR LABORATORY', '8837', 'Closed', 'W Wednesday 9:00 AM–12:00 PM', 'JH 061', 'Adam Fudickar', 0, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Teaches how to observe, quantify, and manipulate animal behavior in a laboratory setting. Practices fundamental experimental techniques used in ethological research.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ABEH-A 400', 'ADVANCED WORKSHOP IN ANIMAL BEHAVIOR', '8025', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 008', 'Lisa Barrett', 20, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Research seminar for advanced animal behavior students. Focuses on an individual research project that culminates in a formal presentation related to the student''s independent research or internship experience. Goal is to improve independent study, problem-solving, research, reading, writing, and oral presentation skills. Students also critically evaluate research in the primary literature and research presentations at the annual Animal Behavior Conference.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('ABEH-A 401', 'TOPICAL ISSUES IN ANIMAL BEHAVIOR', '11266', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'JH 248', 'Ellen Ketterson', 0, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Topics related to the scientific study of animal behavior not studied extensively in other courses. Topics vary.', ARRAY[]::TEXT[], NULL),
    ('ABEH-A 501', 'SEMINAR IN THE INTEGRATIVE STUDY OF ANIMAL BEHAVIOR', '12017', 'Closed', 'F Friday 2:00 PM–3:30 PM', 'HD TBA', 'Dale Sengelaub', 0, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Investigation of functional behavior of animals (e.g., migration, parental behavior, mate choice) using an interdisci­plinary approach that attempts to integrate the perspectives of developmental psychology, ecology and evolutionary biology, neural science, and the science of learning and memory. Topic will vary.', ARRAY[]::TEXT[], NULL),
    ('ABEH-X 473', 'ANIMAL BEHAVIOR INTERNSHIP', '3362', 'Closed', NULL, NULL, 'Adam Fudickar', 0, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Hands-on animal behavior research experience in practical situations. Interns are matched with faculty mentors and internship sites. Students combine research with practical service to the host organization.', ARRAY[]::TEXT[], NULL),
    ('ABEH-X 491', 'INDEPENDENT STUDY IN ANIMAL BEHAVIOR', '8693', 'Class Status', NULL, NULL, 'Cara Wellman', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent study under supervision of a faculty member. Study in depth of a topic of interest to the student, culminating in a research paper and presentation.', ARRAY[]::TEXT[], NULL),
    ('ABEH-X 491', 'INDEPENDENT STUDY IN ANIMAL BEHAVIOR', '36390', 'Class Status', NULL, NULL, 'Erica Cartmill', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent study under supervision of a faculty member. Study in depth of a topic of interest to the student, culminating in a research paper and presentation.', ARRAY[]::TEXT[], NULL),
    ('AERO-A 101', 'HERITAGE AND VALUES OF THE UNITED STATES AIR FORCE I', '1007', 'Class Status', 'Th Thursday 1:45 PM–2:35 PM', 'WH 121', 'Nick Warner, Brendan Benning', 32, NULL, 'Lecture', '1', 'WOODBURN HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AERO-A 151', 'AIR FORCE ROTC LEADERSHIP LABORATORY (LLAB) I', '9091', 'Class Status', 'Th Thursday 4:10 PM–7:10 PM', 'JH 009', 'Nick Warner, Mason Jenkins, Tyler Harman', 9, NULL, 'Laboratory', '1', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'The purpose of the Leadership Lab (LLAB) program is to augment the AFROTC academic curriculum by providing prospective Air Force officers the opportunities and feedback needed to develop the leadership, followership, managerial, and supervisory skills required of successful Air Force officers. LLAB is a dynamic and integrated grouping of leadership and professional development activities designed to meet the needs and expectations of prospective Air Force officers and complement the AFROTC academic program. It is a student-planned, student-organized and student-executed practicum conducted under the supervision of the Detachment Commander and Operations Flight Commander/Operations Officer.', ARRAY[]::TEXT[], NULL),
    ('AERO-A 201', 'TEAM AND LEADERSHIP FUNDAMENTALS I', '1008', 'Class Status', 'Th Thursday 12:45 PM–1:35 PM', 'SW 221', 'Mason Jenkins, Nick Warner, Brendan Benning', 6, NULL, 'Lecture', '1', 'SWAIN WEST', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AERO-A 301', 'LEADING PEOPLE AND EFFECTIVE COMMUNICATION I', '1009', 'Class Status', 'Th Thursday 12:45 PM–2:45 PM', 'HD TBA', 'Nick Warner, Mason Jenkins', 10, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AERO-A 401', 'NATIONAL SECURITY AND PREPARATION FOR ACTIVE DUTY I', '1010', 'Class Status', 'Tu Tuesday 12:45 PM–2:45 PM', 'BH 333', 'Nick Warner, Tyler Harman', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Analysis of the United States foreign and defense policies, with emphasis on the study of international alliances and case studies on policy formulation. Other topics include societal attitudes toward the military, the military officer in the democratic society, the requisites for maintaining national security, constraints on the defense establishment, and military law. Case studies are included.', ARRAY[]::TEXT[], NULL),
    ('AFRI-A 100', 'INTRODUCTION TO AFRICAN STUDIES', '14946', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GY 1043', 'Emily Stratton', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Interdisciplinary introduction to African Studies, with topics focusing on history, geography, life-ways, music, religion, philosophy, literature, and the visual arts. Critically examines the framing of Africa in the Global North and modes of knowledge production about Africa. Provides foundation for further coursework in African Studies.', ARRAY['IUB GenEd World Culture credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AFRI-A 500', 'ADVANCED TOPICS IN AFRICAN STUDIES', '6380', 'Class Status', NULL, NULL, 'Barbaro Martinez-Ruiz', 6, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Advanced and intensive study of selected topics in African Studies. To include topics not ordinarily covered by existing African Studies Program courses. May not duplicate a regularly offered course.', ARRAY[]::TEXT[], NULL),
    ('AFRI-A 651', 'INDEPENDENT RESEARCH / DIRECTED READINGS', '3635', 'Class Status', NULL, NULL, 'Barbaro Martinez-Ruiz', 6, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individually designed course in preparation for and writing of M.A. thesis. Must be directed by an African Studies faculty affiliate and approved by the student''s disciplinary advisor and the African Studies Program director. May include fieldwork in Africa and/or research in museums, archives, and libraries.', ARRAY[]::TEXT[], NULL),
    ('AFRI-A 731', 'SEMINAR ON CONTEMPORARY AFRICA', '29656', 'Class Status', 'W Wednesday 5:30 PM–8:00 PM', 'ED 1235', 'Beth Samuelson', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'AFRI-A 731 seminars are interdisciplinary graduate courses offered on a different topic by African Studies faculty across the disciplines and professional schools. They include intensive readings and guest lectures by national and international scholars.', ARRAY[]::TEXT[], NULL),
    ('AFRI-B 101', 'ELEMENTARY BAMANA I', '2069', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'FR C230 FR C230', 'Amadou Sow', 13, NULL, 'Lecture', '4', 'FOREST QUAD', ARRAY[]::TEXT[], 'Introduction to Bamana, a Mande language of West Africa, and aspects of Bamana culture. Basic grammatical structures and vocabulary. Emphasis on the spoken language.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-B 201', 'INTERMEDIATE BAMANA I', '2070', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FR C230', 'Amadou Sow', 7, NULL, 'Lecture', '3', 'FOREST QUAD', ARRAY[]::TEXT[], 'Study of more complex grammatical structures with emphasis on active skills: speaking and writing. Reading of elementary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-B 301', 'ADVANCED BAMANA I', '2071', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 016', 'Amadou Sow', 14, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Examination of subtle nuances in grammatical structures. Advanced readings of traditional and modern literature. Composition. Oriented to needs of students enrolled.', ARRAY[]::TEXT[], NULL),
    ('AFRI-B 501', 'ELEMENTARY BAMANA I', '5032', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'FR C230 FR C230', 'Amadou Sow', 13, NULL, 'Lecture', '3', 'FOREST QUAD', ARRAY[]::TEXT[], 'Introduction to Bamana, major language spoken in Mali and Burkina Faso. Basic grammatical structures and vocabulary. Emphasis is on spoken language, language use in specific social settings. Graduate students will have an individual project to complete. Important cultural points like food, clothing, etc. Videos and internet resources will be used.', ARRAY[]::TEXT[], NULL),
    ('AFRI-B 601', 'INTERMEDIATE BAMANA I', '5033', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FR C230', 'Amadou Sow', 7, NULL, 'Lecture', '3', 'FOREST QUAD', ARRAY[]::TEXT[], 'Studying more complex grammatical structures,emphasis speaking/ writing/reading texts, oral/written compositions, reading, listening comprehension,translation of texts. Cultural events through use of videos, CD-ROMs, Internet.', ARRAY[]::TEXT[], NULL),
    ('AFRI-B 701', 'ADVANCED BAMANA I', '5034', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 016', 'Amadou Sow', 14, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course is the first part of a two-semester course. Study of more complex grammatical structures, complex contextual discourse patterns. Advanced readings of traditional, modern literature. Advanced oral, written compositions, listening comprehension, translations. Special projects.', ARRAY[]::TEXT[], NULL),
    ('AFRI-K 101', 'ELEMENTARY AKAN I', '11184', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'FQ B002 FQ B002', 'Seth Ofori', 8, NULL, 'Lecture', '4', 'MARTIN HALL', ARRAY[]::TEXT[], 'Introduction to Akan, a major language of West Africa, spoken by the Akan peoples of Ghana. With approximately three million speakers, it is the major language of Ghana. Also spoken by thousands of people in the Ivory Coast. Basic grammatical structures and vocabulary. Emphasis on the spoken language.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-K 101', 'ELEMENTARY AKAN I', '11591', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Seth Ofori', 15, NULL, 'Lecture', '4', 'MARTIN HALL', ARRAY[]::TEXT[], 'Introduction to Akan, a major language of West Africa, spoken by the Akan peoples of Ghana. With approximately three million speakers, it is the major language of Ghana. Also spoken by thousands of people in the Ivory Coast. Basic grammatical structures and vocabulary. Emphasis on the spoken language.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-K 201', 'INTERMEDIATE AKAN I', '6967', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PY 113', 'Seth Ofori', 10, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Study of more complex grammatical structures, with emphasis on active skills, speaking and writing. Reading of elementary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-K 201', 'INTERMEDIATE AKAN I', '12787', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Seth Ofori', 4, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Study of more complex grammatical structures, with emphasis on active skills, speaking and writing. Reading of elementary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-K 301', 'ADVANCED AKAN I', '11185', 'Class Status', NULL, NULL, 'Seth Ofori', 10, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Examination of subtle nuances in grammatical structures. Advanced readings of traditional and modern literature.', ARRAY[]::TEXT[], NULL),
    ('AFRI-K 501', 'ELEMENTARY AKAN I', '11415', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'FQ B002 FQ B002', 'Seth Ofori', 8, NULL, 'Lecture', '3', 'MARTIN HALL', ARRAY[]::TEXT[], 'Introduction to Akan, major language in Ghana. Basic grammatical structures, vocabulary, emphasis on the spoken language, oral, listening comprehension, language use in specific social settings. Graduate students will have individual projects to submit. Important cultural points like food, clothing, marriage, etc. Videos and Internet resources will be used.', ARRAY[]::TEXT[], NULL),
    ('AFRI-K 601', 'INTERMEDIATE AKAN I', '6968', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PY 113', 'Seth Ofori', 10, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Study of more complex grammatical structures, with emphasis on active skills: speaking and writing. Attention will be on oral and written compositions, reading and listening comprehension, and translation of texts. Description of cultural events through the use of videos and the Internet.', ARRAY[]::TEXT[], NULL),
    ('AFRI-K 601', 'INTERMEDIATE AKAN I', '12788', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Seth Ofori', 4, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Study of more complex grammatical structures, with emphasis on active skills: speaking and writing. Attention will be on oral and written compositions, reading and listening comprehension, and translation of texts. Description of cultural events through the use of videos and the Internet.', ARRAY[]::TEXT[], NULL),
    ('AFRI-K 701', 'ADVANCED AKAN I', '11416', 'Class Status', NULL, NULL, 'Seth Ofori', 10, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Study of more complex grammatical structures and complex contextual discourse patterns. Advanced readings of traditional and modern literature. Advanced oral and written compositions, advanced listening comprehension and translation of complex texts. Use of Internet resources. The course will be completely oriented to the needs of the students enrolled.', ARRAY[]::TEXT[], NULL),
    ('AFRI-L 100', 'TOPICS IN AFRICAN SOCIETY AND CULTURE', '15197', 'Class Status', 'MW Monday, Wednesday 3:10 PM–5:40 PM', 'RA B111', 'Seth Ofori', 24, NULL, 'Lecture', '3', 'SPRUCE HALL', ARRAY[]::TEXT[], 'Study of selected topics in African studies not covered in existing regularly scheduled courses.', ARRAY['COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AFRI-L 100', 'TOPICS IN AFRICAN SOCIETY AND CULTURE', '14098', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GA 0013', 'Bongeka Selepe', 0, NULL, 'Lecture', '3', 'SPRUCE HALL', ARRAY[]::TEXT[], 'Study of selected topics in African studies not covered in existing regularly scheduled courses.', ARRAY['COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AFRI-L 101', 'YOUTH MIGRATION & POLITICAL LEADERSHIP IN AFRICA', '14572', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BQ C129', 'Amadou Sow', 2, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Provides an overview of the narratives and persistent questions about youth migration and political leadership on the African continent, which contains the largest population of displaced persons in the world. Focuses on the role played by political leaders, their timidity and limitation vis-à-vis youth migration in Africa.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AFRI-L 232', 'CONTEMPORARY AFRICA', '8838', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'TE F104', 'Ibrahim Odugbemi', 1, NULL, 'Lecture', '3', 'TETER QUAD', ARRAY[]::TEXT[], 'An introduction to current social, economic, and political issues in Africa.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AFRI-L 250', 'AFRICAN EXPRESSIVE ROUTINES', '32550', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'SW 219', 'Bongeka Selepe', 15, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Introduction to selected oral art forms and traditions of some Sub-Saharan African societies. Emphasis is on the esthetics and communicational mores that regulate the people''s verbal behavior. Enhances understanding and appreciation of African interactional practices, especially, verbal artistry and expressive culture.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AFRI-L 400', 'TOPICS IN AFRICAN STUDIES', '29756', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AC C118', 'Nana Amoah-Ramey', 28, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Intensive study of selected topics in African studies. Studies in special topics not ordinarily covered by African Studies program courses. May not duplicate a regularly offered course. Topics vary.', ARRAY['COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('AFRI-L 506', 'TUTORIAL INSTRUCTION IN FOREIGN LANGUAGES', '2082', 'Class Status', NULL, NULL, 'Beatrice Okelo', 8, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'This is a fourth year course intended to consolidate students'' language and culture knowledge, and proficiency; and promote the level of proficiency to Advanced High, per ACTFL guidelines. It is an individualized language instruction in specific languages.', ARRAY[]::TEXT[], NULL),
    ('AFRI-S 101', 'ELEMENTARY SWAHILI 1', '7829', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'WH 119 AC C118', 'Beatrice Okelo', 7, NULL, 'Lecture', '4', 'WOODBURN HALL, CEDAR HALL', ARRAY[]::TEXT[], 'Introduction to Swahili, a Bantu language spoken in east Africa, and to aspects of Bantu culture. Basic grammatical structures and vocabulary. Emphasis on the spoken language.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-S 201', 'INTERMEDIATE SWAHILI 1', '7830', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'WH 114', 'Beatrice Okelo', 4, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Study of more complex grammatical structures with emphasis on active skills: speaking and writing. Reading of elementary texts.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-S 301', 'ADVANCED SWAHILI 1', '2087', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 015', 'Beatrice Okelo', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examination of subtle nuances in grammatical structures. Advanced readings of traditional and modern literature. Composition. Oriented to needs of students enrolled.', ARRAY[]::TEXT[], NULL),
    ('AFRI-S 501', 'ELEMENTARY SWAHILI I', '5029', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'WH 119 AC C118', 'Beatrice Okelo', 7, NULL, 'Lecture', '3', 'WOODBURN HALL, CEDAR HALL', ARRAY[]::TEXT[], 'Introduction to Swahili, a major African language spoken in East Africa, e.g., Kenya, Tanzania, and Uganda. Basic grammatical structures and vocabulary. Emphasis on spoken language and listening comprehension, language use in specific social settings, and appropriate cultural features (e.g., foods, clothing, marriage, etc.). Student projects.', ARRAY[]::TEXT[], NULL),
    ('AFRI-S 601', 'INTERMEDIATE SWAHILI I', '5030', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'WH 114', 'Beatrice Okelo', 4, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduction of more grammatical structures, expanded vocabulary. Continued work on comprehension, both listening and reading, and oral production. More emphasis on speaking and writing. Student projects.', ARRAY[]::TEXT[], NULL),
    ('AFRI-S 701', 'ADVANCED SWAHILI I', '5031', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 015', 'Beatrice Okelo', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course is the first part of a two-semester course. Study of more complex grammatical structures and of more complex contextual discourse patterns. Advanced readings of oral and written compositions, advanced listening comprehension, and translation of complex texts. Use of Internet resources.', ARRAY[]::TEXT[], NULL),
    ('AFRI-X 390', 'READINGS AND RESEARCH IN AFRICAN STUDIES', '5062', 'Class Status', NULL, NULL, 'Nana Amoah-Ramey', 8, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent readings or research project in African Studies.', ARRAY[]::TEXT[], NULL),
    ('AFRI-X 391', 'INDIVIDUAL STUDY OF AN AFRICAN LANGUAGE', '14097', 'Class Status', NULL, NULL, 'Beatrice Okelo', 8, NULL, 'Lecture', '1–4', NULL, ARRAY[]::TEXT[], 'Individual study of an African language for variable credit.', ARRAY[]::TEXT[], NULL),
    ('AFRI-X 473', 'INTERNSHIP IN AFRICAN STUDIES', '5035', 'Class Status', NULL, NULL, 'Nana Amoah-Ramey', 8, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Provides students with an opportunity to receive academic credit for work/service in an organization in Africa, or in a U.S. based organization focused on Africa or working with an African constituency. Requires a research paper related to the internship.', ARRAY[]::TEXT[], NULL),
    ('AFRI-X 491', 'POST ADVANCED INDIVIDUAL STUDY OF AN AFRICAN LANGUAGE', '7915', 'Class Status', NULL, NULL, 'Beatrice Okelo', 7, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Advanced individual study of an African language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('AFRI-X 491', 'POST ADVANCED INDIVIDUAL STUDY OF AN AFRICAN LANGUAGE', '34596', 'Class Status', NULL, NULL, 'Matthew Ajibade', 3, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Advanced individual study of an African language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('AFRI-X 773', 'GRADUATE INTERNSHIP IN AFRICAN STUDIES', '9777', 'Class Status', NULL, NULL, 'Barbaro Martinez-Ruiz', 5, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Provides graduate students with opportunity to receive academic credit for work/service through an organization in Africa or in the U.S. focused on Africa or working with an African constituency. Requires a paper related to the internship.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Y 101', 'ELEMENTARY YORUBA I', '5854', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 0011 BQ C232', 'Matthew Ajibade', 0, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES, BRISCOE QUAD', ARRAY[]::TEXT[], 'Introduction to Yoruba language, a major African language spoken in Nigeria. Basic grammatical structures and vocabulary. Emphasis on spoken language, listening comprehension, language used in everyday life and in specific social settings.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-Y 201', 'INTERMEDIATE YORUBA I', '35118', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Matthew Ajibade', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Study of more complex grammatical structures, with emphasis on the active skills of speaking and writing. Reading and translation of elementary texts. Survey of cultural activities.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-Y 201', 'INTERMEDIATE YORUBA I', '6284', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GA 0011', 'Matthew Ajibade', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Study of more complex grammatical structures, with emphasis on the active skills of speaking and writing. Reading and translation of elementary texts. Survey of cultural activities.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-Y 301', 'ADVANCED YORUBA I', '6657', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 270', 'Matthew Ajibade', 5, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Study of more complex grammatical structures and contextual discourse patterns. Advanced readings of traditional and modern literature. Advanced oral and written compositions. Listening and reading comprehension of complex texts.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Y 501', 'ELEMENTARY YORUBA I', '5970', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 0011 BQ C232', 'Matthew Ajibade', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES, BRISCOE QUAD', ARRAY[]::TEXT[], 'First of a two-semester sequence. Introduction to Yoruba language and culture, a major African language spoken in Nigeria. Basic grammatical structures and vocabulary. Emphasis on spoken language and listening comprehension, language use in specific social settings (e.g., market, hospital, school), and appropriate cultural features (e.g., foods, marriage, etc.). Student projects.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Y 601', 'INTERMEDIATE YORUBA I', '6285', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GA 0011', 'Matthew Ajibade', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'First part of a two-semester sequence. Introduction of more complex grammatical structures, expanded vocabulary. Continued work on comprehension, both listening and reading, and oral production. More emphasis on speaking and writing. Student projects.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Y 701', 'ADVANCED YORUBA I', '6740', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 270', 'Matthew Ajibade', 5, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Study of more complex grammatical structures and more complex contextual discourse patterns. Advanced readings of traditional and modern literature. Advanced oral and written compositions, advanced listening and reading comprehension of complex texts. Students will do additional work linked to their majors.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Z 201', 'INTERMEDIATE ZULU I', '3135', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'AC C118', 'Bongeka Selepe', 6, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Study of more complex grammatical structures, with emphasis on active skills of speaking, writing and reading texts. Emphasis on oral and written compositions, reading and listening comprehension, and translation of texts. Description of cultural events through the use of videos and the internet resources.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-Z 201', 'INTERMEDIATE ZULU I', '12967', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WB WEB', 'Bongeka Selepe', 10, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Study of more complex grammatical structures, with emphasis on active skills of speaking, writing and reading texts. Emphasis on oral and written compositions, reading and listening comprehension, and translation of texts. Description of cultural events through the use of videos and the internet resources.', ARRAY['IUB GenEd World Language class'], NULL),
    ('AFRI-Z 301', 'ADVANCED ZULU I', '3116', 'Class Status', NULL, NULL, 'Bongeka Selepe', 10, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Study of more complex grammatical structures and of more complex contextual discourse patterns. Advanced readings of traditional and modern literature. Advanced oral and written compositions, advanced listening comprehension and translation of complex texts. Uses videos and internet resources.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Z 301', 'ADVANCED ZULU I', '12968', 'Class Status', NULL, 'WB WEB', 'Bongeka Selepe', 10, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Study of more complex grammatical structures and of more complex contextual discourse patterns. Advanced readings of traditional and modern literature. Advanced oral and written compositions, advanced listening comprehension and translation of complex texts. Uses videos and internet resources.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Z 501', 'ELEMENTARY ZULU I', '4526', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'GA 3018 GA 3018', 'Bongeka Selepe', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to Zulu, a major African language spoken in South Africa. Basic grammatical structures and vocabulary. Emphasis on spoken language and listening comprehension, language use in specific social settings, and appropriate cultural features (e.g., foods, clothing, marriage, etc.). Student projects.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Z 501', 'ELEMENTARY ZULU I', '12969', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Bongeka Selepe', 10, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to Zulu, a major African language spoken in South Africa. Basic grammatical structures and vocabulary. Emphasis on spoken language and listening comprehension, language use in specific social settings, and appropriate cultural features (e.g., foods, clothing, marriage, etc.). Student projects.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Z 601', 'INTERMEDIATE ZULU I', '3153', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'AC C118', 'Bongeka Selepe', 1, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'The first part of a two-semester sequence. Study of more complex grammatical structures, with emphasis on active skills: speaking, writing, and reading texts. Attention will be on oral and written compositions, and translation of texts. Description of cultural events through the use of videos and the Internet.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Z 601', 'INTERMEDIATE ZULU I', '12970', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WB WEB', 'Bongeka Selepe', 10, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'The first part of a two-semester sequence. Study of more complex grammatical structures, with emphasis on active skills: speaking, writing, and reading texts. Attention will be on oral and written compositions, and translation of texts. Description of cultural events through the use of videos and the Internet.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Z 701', 'ADVANCED ZULU I', '3154', 'Class Status', NULL, NULL, 'Bongeka Selepe', 10, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'First of a two-semester sequence. More complex grammatical structures and contextual discourse patterns. Advanced readings of traditional and modern literature. Advanced oral and written compositions, advanced listening comprehension and translation of complex texts. Use of internet resources. The course will be completely oriented to the needs of those enrolled.', ARRAY[]::TEXT[], NULL),
    ('AFRI-Z 701', 'ADVANCED ZULU I', '11854', 'Class Status', NULL, 'WB WEB', 'Bongeka Selepe', 10, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'First of a two-semester sequence. More complex grammatical structures and contextual discourse patterns. Advanced readings of traditional and modern literature. Advanced oral and written compositions, advanced listening comprehension and translation of complex texts. Use of internet resources. The course will be completely oriented to the needs of those enrolled.', ARRAY[]::TEXT[], NULL),
