    ('AMST-A 202', 'U.S. ARTS AND MEDIA', '8794', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 243', 'Paul Anderson', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Interdisciplinary approaches to a cultural genre (e.g. science fiction, pop art, jazz), discourse (e.g. individualism, family values, globalization) or medium (e.g. comics, television, the internet). Constructing, deconstructing, reconstructing an object of cultural study. Recent topics have included Images of the Body, Jazz and Cultural Hierarch, and Youth Cultures.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('AMST-A 298', 'SPECIAL TOPICS IN ARTS AND HUMANITIES FOR AMERICAN STUDIES', '14609', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 243', 'Susan Lepselter', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study and analysis of a single, closely-focused American studies topic within arts and humanities. Topics vary from semester to semester. Focuses on the refinement of students'' skills in writing, interdisciplinary interpretation, analytical reasoning, discussion, and research related to the study of fine arts, literature, film, and popular culture.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('AMST-A 350', 'TOPICS IN INTERDISCIPLINARY AMERICAN STUDIES', '10023', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 344', 'Sasha Weiss', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduces established American studies disciplinary methodologies and explores possibilities for new interdisciplinary syntheses by focusing on specific topics, which vary by semester.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('AMST-G 520', 'TOPICS IN INTERDISCIPLINARY AMERICAN STUDIES', '30455', 'Class Status', 'M Monday 3:10 PM–5:10 PM', 'SY 006', 'Alex Lichtenstein', 3, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Focusing on a specific topic, reflect on established AMST disciplinary methodologies and explore possibilities for new interdisciplinary syntheses. Consider issues like the questions historians ask and how they differ from those of literary critics or sociologists.', ARRAY[]::TEXT[], NULL),
    ('AMST-G 751', 'SEMINAR IN AMERICAN STUDIES', '10537', 'Class Status', 'Th Thursday 3:10 PM–5:40 PM', 'BH 503', 'Cynthia Wu', 1, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Intensive study of specific topics in American culture and history with emphasis on developing skills in interdisciplinary research. These seminars will culminate in a 20+-page research paper. Topics and instructors will change each time the seminar is offered.', ARRAY[]::TEXT[], NULL),
    ('AMST-G 753', 'INDEPENDENT STUDY', '9295', 'Class Status', NULL, NULL, 'Susan Lepselter', 2, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AMST-G 805', 'PHD THESIS', '9132', 'Closed', NULL, NULL, 'Susan Lepselter', 0, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AMST-G 901', 'ADVANCED RESEARCH', '1014', 'Class Status', NULL, NULL, 'Susan Lepselter', 10, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('AMST-X 390', 'READINGS IN AMERICAN STUDIES', '15061', 'Class Status', 'F Friday 12:45 PM–1:35 PM', 'HD TBA', 'Michael Ing', 12, NULL, 'Lecture', '1–3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Enables undergraduates of advanced standing to undertake independent research projects under the direction of an American Studies faculty member. Students will typically arrange for 1 to 3 credit hours of work, depending upon the scope and depth of reading, research, and production. Projects will be interdisciplinary, and should foreground topics clearly within the rubric of American Studies.', ARRAY[]::TEXT[], NULL),
    ('ANAT-A 225', 'HUMAN ANATOMY', '13863', 'Closed', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'BH 013', 'Valerie O''Loughlin', 0, 'Lecture', 'Lecture', '5', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course presents a systemic approach to studying the human body. Students learn the gross and microscopic anatomy of the following systems: integumentary, skeletal, muscular, nervous, circulatory, lymphatic, respiratory, digestive, endocrine, urinary, and reproductive. The lab component is face-to-face only and reinforces lecture using models, slides, bones, and cadaver demonstration.', ARRAY['IUB GenEd N&M credit - Natural Science
Class uses IU eTexts'], NULL),
