    ('ANAT-A 455', 'INTRODUCTION TO CLINICAL NEUROANATOMY', '32600', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'AH C3062', 'Stacey Dunham', 14, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Introduction to Clinical Neuroanatomy provides a comprehensive overview of neuroanatomy. Before each class, students will complete online Functional Neuroanatomy modules from The University of British Columbia. In-class students will further extend their knowledge through laboratories, clinical case studies, and digital imaging tools.', ARRAY[]::TEXT[], NULL),
    ('ANAT-A 464', 'HUMAN TISSUE BIOLOGY', '9726', 'Class Status', NULL, 'WB WEB', 'John Foley', 1, 'Lecture', 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Microscopic structure of mammalian (with emphasis on human) tissues and organs.', ARRAY[]::TEXT[], NULL),
    ('ANAT-A 464', 'HUMAN TISSUE BIOLOGY', '9727', 'Class Status', NULL, 'WB WEB', 'John Foley', 1, 'Laboratory', 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Microscopic structure of mammalian (with emphasis on human) tissues and organs.', ARRAY[]::TEXT[], NULL),
    ('ANAT-A 515', 'BASIC HUMAN ANATOMY FOR EDUCATORS', '9168', 'Class Status', NULL, NULL, 'Stacey Dunham, Valerie O''Loughlin, Kathryn Propst, Danielle Hanson', 10, NULL, 'Lecture', '5', NULL, ARRAY[]::TEXT[], 'Systems-based human anatomy course designed for graduate students who will be teaching basic undergraduate human anatomy courses. Students will learn gross and microscopic anatomy of the following systems: skeletal, muscular, nervous, circulatory, respiratory, digestive, urinary and reproductive. Lecture meets three times weekly, and a 2-hr lab meets twice weekly.', ARRAY['Class uses IU eTexts'], NULL),
    ('ANAT-A 530', 'SPECIAL TOPICS', '1015', 'Class Status', NULL, NULL, 'Polly Husmann, Valerie O''Loughlin, Stacey Dunham, Jim Davis', 1, NULL, 'Lecture', '1–5', NULL, ARRAY[]::TEXT[], 'Readings course to be completed with a faculty member.', ARRAY[]::TEXT[], NULL),
    ('ANAT-A 555', 'INTRODUCTION TO CLINICAL NEUROANATOMY', '32617', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'AH C3062', 'Stacey Dunham', 2, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Introduction to Clinical Neuroanatomy provides a comprehensive overview of neuroanatomy. Before each class, students will complete online Functional Neuroanatomy modules from The University of British Columbia. In-class students will further extend their knowledge through laboratories, clinical case studies, and digital imaging tools.', ARRAY[]::TEXT[], NULL),
    ('ANAT-A 620', 'HUMAN STRUCTURE', '7620', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 12:50 PM–4:50 PM', 'HD TBA', 'Polly Husmann, John Foley, Stacey Dunham, Valerie O''Loughlin', 9, NULL, 'Lecture', '9', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Explores developmental processes (embryology)and microscopic-to-macroscopic structural organization of the human body. Course is subdivided into didactic (lecture) and lab (both histology and gross anatomy) components. Cadaveric dissection and virtual microscopy, along with medical imaging, are utilized.', ARRAY[]::TEXT[], NULL),
    ('ANAT-A 800', 'RESEARCH IN ANATOMY', '1016', 'Class Status', NULL, NULL, 'Polly Husmann, Valerie O''Loughlin, Stacey Dunham', 5, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ANAT-A 850', 'TOPICAL SEMINAR IN ANATOMY', '1017', 'Class Status', 'F Friday 11:40 AM–12:40 PM', 'AH C3101', 'Polly Husmann, Stacey Dunham, Valerie O''Loughlin', 5, NULL, 'Seminar', '1', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Topics of current interest discussed in seminar format.', ARRAY[]::TEXT[], NULL),
    ('ANAT-A 878', 'ANATOMY TEACHING PRACTICUM', '4579', 'Class Status', NULL, NULL, 'Polly Husmann, Valerie O''Loughlin, Stacey Dunham', 12, NULL, 'Internship', '2', NULL, ARRAY[]::TEXT[], 'Supervised teaching in an upper-level undergraduate or graduate/medical anatomy-related course offered at IUSM-Bloomington. Teaching may involve being instructor of record, lecturing, and/or lab instruction.', ARRAY[]::TEXT[], NULL),
    ('ANTH-A 107', 'BECOMING HUMAN: EVOLVING GENES, BODIES, BEHAVIORS, IDEAS', '32673', 'Closed', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'SB 150', 'Thomas Siek', 0, 'Lecture', 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Introduces the interdisciplinary science of human evolution using evidence from genetics, comparative anatomy and behavior of living primates, fossils, and archaeology. Shows how understanding the evolutionary past is relevant to current and future human conditions.', ARRAY['IUB GenEd N&M credit - Natural Science
