    ('ANTH-A 200', 'TOPICS IN ANTHROPOLOGY OF CULTURE AND SOCIETY', '35011', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'LH 328', 'Lessie Frazier', 2, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Selected topics in the anthropological study of social and cultural institutions. Emphasizes understanding and developing anthropological approaches to questions about social, economic, political, and historical relationships among groups and individuals in contexts across the globe. Course topics may utilize ethnographic, archaeological, linguistic, and historical information.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ANTH-A 211', 'ANTHROPOLOGY TOPICS IN THE NATURAL AND MATHEMTICAL SCIENCES', '30073', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 203', 'Frederika Kaestle', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Selected topics in anthropology that explore human interaction with physical and biological environments, or apply scientific methodology to anthropological questions. May emphasize human evolution and biology, nutrition, forensics, non-human primates, technology, archaeometry, and other scientific measurement, experimentation, and inquiry as it relates to anthropological study.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('ANTH-A 399', 'HONORS TUTORIAL', '1018', 'Class Status', NULL, NULL, 'Jane Goodman', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Research and writing, culminating in Honors thesis.', ARRAY[]::TEXT[], NULL),
    ('ANTH-A 405', 'MUSEUM METHODS', '33333', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'C2 102', 'Jason Jackson', 0, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Methods and techniques of museum design, administration, accessioning, conservation and restoration, acquisition of specimens, curatorial work, exhibition and education.', ARRAY[]::TEXT[], NULL),
    ('ANTH-A 521', 'INTRODUCTION TO COLLEGE TEACHING, INTERDISCIPLINARY APPROACHES', '1019', 'Class Status', 'F Friday 8:30 AM–11:00 AM', 'SB 140', 'Jennifer Robinson', 2, NULL, 'Seminar', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'This seminar will help graduate students become more effective educators and to spark ongoing interest in the intellectual challenges and possibilities that teaching presents. Theory and practice in college teaching will help participants become more intentional and more informed about interdisciplinary possibilities and disciplinary distinctions in college teaching.', ARRAY[]::TEXT[], NULL),
    ('ANTH-A 525', 'COMMUNITY BASED RESEARCH I', '13910', 'Class Status', 'M Monday 12:30 PM–3:00 PM', 'AN 101', 'Keitlyn Alcantara', 3, NULL, 'Seminar', '3', '701 E 8TH ST', ARRAY[]::TEXT[], 'Community based research involves a partnership approach in which responsibility for planning, conducting, and evaluating research is shared with a community. This course provides grounding in community based research methods, examining how they transform social science research. We will explore issues of ethics, power relations, and field work practices.', ARRAY[]::TEXT[], NULL),
    ('ANTH-A 576', 'GRADUATE MUSEUM PRACTICUM', '7065', 'Class Status', NULL, NULL, 'Fumi Arakawa', 10, NULL, 'Practicum', '1–6', NULL, ARRAY[]::TEXT[], 'Anthropology-oriented practicum at a campus or community-based museum or systematic research collection. Participatory activities will be supplemented by reading and writing activities.', ARRAY[]::TEXT[], NULL),
    ('ANTH-A 578', 'GRADUATE INTERNSHIP IN ANTHROPOLOGY', '11387', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Faculty-directed study of anthropological problems based on an internship experience. Student''s area of placement must be related to major field of study. Student may complete more than one internship but the total credit cannot be more than 6 credit hours.', ARRAY[]::TEXT[], NULL),
    ('ANTH-A 595', 'GRADUATE READINGS IN ANTHROPOLOGY', '7217', 'Class Status', NULL, NULL, 'Stacie King', 23, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Individualized course that allows graduate students the opportunity to work one on one with a faculty member to develop expertise in a particular topic/theme/area of study.', ARRAY[]::TEXT[], NULL),
