    ('ANTH-B 301', 'LABORATORY IN BIOANTHROPOLOGY', '30055', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'SB 060', 'Maire O''Malley', 17, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Covers the methods and techniques of bioanthropology. Emphasis is on developing and testing evolutionary hypotheses using contemporary methods. Includes laboratory investigations of human skeletal biology including age and sex determinations and forensic identification; human paleontological and primate observations; variability in living populations including anthropometry, genetics, bloodtyping, demography; among others.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('ANTH-B 312', 'EVOLUTIONARY MEDICINE', '33681', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SB 140', 'James Gibb', 12, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Incorporates principles from evolutionary theory into our understanding of various infectious and chronic diseases common to human populations both past and present. Although proximate mechanisms involving physiology and behavior will be discussed, the focus will be to determine why such mechanisms have evolved in the first place.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('ANTH-B 370', 'HUMAN VARIATION', '30066', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SB 150', 'Frederika Kaestle', 19, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Explores the variation within and between human populations in morphology (anatomy), physiology, genetics, and behavior with a focus on evolutionary processes acting on humans in the past, present and future to shape our body and genes.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('ANTH-B 570', 'HUMAN ADAPTATION: BIOLOGICAL APPROACHES', '30067', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SB 150', 'Frederika Kaestle', 9, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Understanding the concept of adaptation as it is utilized within bioanthropology, anthropology and other disciplines. Focus on individual and population responses to heat, cold, solar radiation, high altitude, nutritional and disease stress. Participation in discussion and presentation of oral and written reports emphasized throughout the seminar.', ARRAY[]::TEXT[], NULL),
    ('ANTH-B 600', 'SEMINAR IN BIOANTHROPOLOGY', '34914', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SB 140', 'James Gibb', 12, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ANTH-E 101', 'SUSTAINABILITY AND SOCIETY', '30006', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SB 150', 'Sarah Osterhoudt', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'How do humans relate to the environment? Addresses this question from cross-cultural, historical, scientific, and ethical perspectives. Considers current problems; examines how technical, socioeconomic and political changes transform peoples'' use of natural resources. Students evaluate how societies vary in perception of nature and explore implications for behavior, decision-making, and environmental change.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Sustainability Literacy credit'], NULL),
    ('ANTH-E 200', 'SOCIAL AND CULTURAL ANTHROPOLOGY', '1022', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SB 150', 'Brian Gilley', 1, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'An introduction to social-cultural anthropology''s history, theories, and analytical approaches to cross-cultural analysis. Covers foundational concepts and ethnographic methods used to understand current issues such as race and racism, ethnicity and nationalism, class and inequality, gender, family and kinship, religion, and people''s relationship to the environment.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Sustainability Literacy credit'], NULL),
    ('ANTH-E 253', 'INTOXICATING CULTURES: ALCOHOL IN EVERYDAY LIFE', '13452', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SB 140', 'Christina Collins', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Explores how alcohol is an "embodied material culture" embedded in everyday life. Asks students to think critically about the relationship between alcohol and culture in both their own lives and in the lives of others.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture
Class uses IU eTexts'], NULL),
    ('ANTH-E 260', 'CULTURE, HEALTH AND ILLNESS', '11727', 'Class Status', 'MW Monday, Wednesday 3:10 PM–4:00 PM', 'EP 257', 'Sarah Phillips', 35, 'Lecture', 'Lecture', '3', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'Across the world, ideas about and experiences of health, "dis-ease," and medicine are profoundly shaped by culture. Introduction to cross-cultural approaches to understanding health and illness, covering topics such as ethnomedicine, ritual healing, gender and health, and international development and global health.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
