    ('ANTH-E 302', 'ETHNOGRAPHIC METHODS', '14606', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SB 140', 'Beth Buggenhagen', 14, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Students learn the approaches and methods of ethnography by conducting their own hands-on field research projects in and around the community. Students complete a series of ethnographic lab assignments on participant observation, mapping and visual technologies, interviewing, and writing up research findings.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ANTH-E 393', 'WORLD FICTION AND CULTURAL ANTHROPOLOGY', '30043', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SB 138', 'Marvin Sterling', 3, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Uses literature and anthropology as a means of understanding culture. Ethnographic writing and world fiction--novels, short stories, poems, myths, folktales--are analyzed to reveal aspects of the social, cultural, and political lives of peoples around the world. Colonialism, war, socialism, and immigration are also discussed.', ARRAY[]::TEXT[], NULL),
    ('ANTH-E 400', 'UNDERGRADUATE SEMINAR', '29647', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0011', 'Lucía Stavig', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intensive examination of selected topics in anthropology. Emphasis on analytic investigation and critical discussion. Topics vary.', ARRAY[]::TEXT[], NULL),
    ('ANTH-E 407', 'VISUAL ANTHROPOLOGY: FILMMAKING', '30077', 'Class Status', 'Tu Tuesday 4:00 PM–6:30 PM', 'LI 044B', 'Elena Guzman', 2, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'Experimental filmmaking concerning social behavior, institutions and customs.', ARRAY[]::TEXT[], NULL),
    ('ANTH-E 412', 'ANTHROPOLOGY OF RUSSIA AND EASTERN EUROPE', '34662', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0009', 'Iryna Voloshyna', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Explores the contradictory effects of socialism''s "fall" through a study of new ethnographies of post-socialist societies. Regional inquiries will be related to broader intellectual issues such as globalization, social suffering, commodification and cultural identity, ethnicity, and nation building, armed conflict, and gender inequalities.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('ANTH-E 418', 'GLOBALIZATION AND CONSUMER CULTURE', '30162', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SB 138', 'Brian Gilley', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Examines processes of globalization and economic and cultural integration, including the origin and spread of mass-consumer society. Topics include the theories of consumption, mass media and advertising, and the relationship between modernity and consumerism. Includes examples from societies around the world.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ANTH-E 421', 'FOOD AND CULTURE', '12143', 'Closed', 'M Monday 9:10 AM–11:40 AM', 'SB 140', 'Christina Collins', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Discussion of the economy of food production, trade and consumption on a global basis. Gives a cross-cultural and historical perspective on the development of cooking and cuisine in relationship to individual, national, and ethnic identity. Relates cuisine to modernity, migration, and forms of cultural mixing and Creolization.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('ANTH-E 456', 'THE ANTHROPOLOGY OF RACE', '30044', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SB 138', 'Marvin Sterling', 11, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Explores race from a cultural anthropological perspective and investigates the history of this idea within the discipline as well as its dissemination in international society. Examines the play between challenges to race as an intellectual paradigm and the resilient status of race-thinking in society at large.', ARRAY[]::TEXT[], NULL),
    ('ANTH-E 600', 'SEMINAR IN CULTURAL AND SOCIAL ANTHROPOLOGY', '34002', 'Class Status', 'Tu Tuesday 4:00 PM–6:30 PM', 'LI 044B', 'Elena Guzman', 1, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ANTH-E 600', 'SEMINAR IN CULTURAL AND SOCIAL ANTHROPOLOGY', '34836', 'Class Status', 'Tu Tuesday 3:00 PM–5:00 PM', 'HD TBA', 'Jessica Steinberg', 2, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ANTH-E 612', 'ANTHROPOLOGY OF RUSSIA AND EAST EUROPE', '34663', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0009', 'Iryna Voloshyna', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Explores the contradictory effects of socialism''s "fall" through a study of new ethnographies of post-socialist societies. We will connect our inquiries to broad intellectual questions in anthropology and related disciplines, including globalization, social suffering, commodification and cultural identity, ethnicity and nation building, armed conflict, and gender inequalities', ARRAY[]::TEXT[], NULL),
    ('ANTH-E 621', 'FOOD AND CULTURE', '12144', 'Closed', 'M Monday 9:10 AM–11:40 AM', 'SB 140', 'Christina Collins', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Discusses the political economy of food production, trade and consumption on a global basis. Gives a cross cultural and historical perspective on the development of cooking and cuisine in relationship to individual, national, and ethnic identity. Relates cuisine to modernity, migration and forms of cultural mixing and Creolizaiton.', ARRAY['Class uses IU eTexts'], NULL),
    ('ANTH-E 656', 'THE ANTHROPOLOGY OF RACE', '30045', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SB 138', 'Marvin Sterling', 1, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'This course explores race in cultural anthropological perspective. It investigates the history of this idea within the discipline as well as its dissemination in international society. The course explores the play between challenges to race as an intellectual paradigm and the resilient status of race-thinking in society at large.', ARRAY[]::TEXT[], NULL),
    ('ANTH-E 663', 'MUSEUM EXHIBITIONS: CULTURES AND PRACTICES', '14833', 'Class Status', 'Tu Tuesday 11:35 AM–2:05 PM', 'FX 150', 'Beth Buggenhagen', 3, NULL, 'Seminar', '3', 'MCCALLA', ARRAY[]::TEXT[], 'The course considers exhibitions and the institutions, histories, values, and curatorial practices that shape them and that are also shaped by them. The course introduces exhibition curation techniques and incorporates hands-on exercises. Students will leverage critical exhibition scholarship for the practical work of collaboratively developing effective and relevant exhibition projects.', ARRAY[]::TEXT[], NULL),
    ('ANTH-G 599', 'THESIS RESEARCH', '3075', 'Class Status', NULL, NULL, 'Stacie King', 25, NULL, 'Independent Study', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('ANTH-G 901', 'ADVANCED RESEARCH', '1023', 'Class Status', NULL, NULL, 'Stacie King', 45, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('ANTH-H 500', 'HIST ANTH THGHT 19TH-20TH CENT', '30155', 'Class Status', 'W Wednesday 12:45 PM–3:15 PM', 'SB 159', 'Marvin Sterling', 5, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ANTH-L 200', 'LANGUAGE AND CULTURE', '5486', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SB 150', 'Daniel Suslak', 1, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'An introduction to the field of linguistic anthropology, the social scientific study of language. Examines how languages reflect cultures, how language use reproduces culture(s), how linguistic categories relate to categories of thought, and how linguistic variation both reflects and shapes social categories such as gender, class, race, and ethnicity.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ANTH-L 314', 'PERFORMANCE AS COMMUNICATVE PRAC', '30053', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'SB 017', 'Jane Goodman', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Introduction to performance as a communicative practice, focusing on performance as a special, artistic mode of communication and performance as a special class of display events in which the values and symbols of a culture are enacted before an audience.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ANTH-L 410', 'LANGUAGE AND SOCIETY IN CENTRAL EURASIA', '29785', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 112', 'Kathryn Graber', 1, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This seminar explores how language is used to accomplish economic, political, and sociocultural ends in Central Eurasia. Topics covered include multilingualism; regional ethnolinguistic categories; the relationship between language policy and nationalities policy; gendered language; code choice in interactions; the politics of translation; poetics; standardization; and language shift, endangerment, and revitalization.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('ANTH-L 500', 'PROSEMINAR IN LANGUAGE AND CULTURE', '30137', 'Class Status', 'Tu Tuesday 4:20 PM–6:50 PM', 'SB 138', 'Daniel Suslak', 7, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ANTH-L 610', 'LANGUAGE AND SOCIETY IN CENTRAL EURASIA', '29786', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 112', 'Kathryn Graber', 2, NULL, 'Seminar', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This seminar explores how language is used to accomplish economic, political, and sociocultural ends in Central Eurasia. Topics covered include multilingualism; regional ethnolinguistic categories; the relationship between language policy and nationalities policy; gendered language; code choice in interactions; the politics of translation; poetics; standardization; and language shift, endangerment, and revitalization.', ARRAY[]::TEXT[], NULL),
    ('ANTH-P 200', 'INTRODUCTION TO ARCHAEOLOGY', '1024', 'Class Status', 'TuTh Tuesday, Thursday 11:35 AM–12:25 PM', 'GA 1118', 'Fumi Arakawa', 4, 'Lecture', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to the goals, methods, and theories that archaeologists use to learn about the past. The pursuit and interpretation of archaeological evidence are explored by reviewing case studies from across the globe and diverse time periods. Topics include food and subsistence, culture change, social life, political economies, and archaeological ethics.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
