    ('ANTH-P 305', 'UNDERWATER ARCHAEOLOGY', '34399', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'ED 0101', 'Kirsten Hawley', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An overview of the field of Underwater Archaeology and the study of underwater cultural heritage. Topics include theoretical background, ethics, methodologies used to analyze submerged archaeological material, conservation, and case studies from the field.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ANTH-P 330', 'HISTORICAL ARCHAEOLOGY', '30159', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SB 050', 'Ryan Kennedy', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Examines archaeology in North America beginning with the long and complex history of Native American/European interactions. Considers North American social systems, interaction with and exploitation of the environment, technologies, and material culture. Theories and methods used by historical archaeologists will also be emphasized.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ANTH-P 380', 'PREHISTORIC DIET AND NUTRITION', '30052', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SB 050', 'Keitlyn Alcantara', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'How the long-term history of human diet has influenced our genetic, physiological, cultural and socio-economic development. Evolutionary and ecological perspectives on modern human diet and nutrition, including (1) survey of modern human and non-human primate diets; (2) the record of prehistoric human diet and methods of dietary reconstruction.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('ANTH-P 399', 'UNDERGRADUATE SEMINAR', '30134', 'Class Status', 'W Wednesday 9:10 AM–11:40 AM', 'SB 140', 'Stacie King', 18, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Intensive examination of selected topics in archaeology. Development of skills in analysis and criticism. Topic varies.', ARRAY[]::TEXT[], NULL),
    ('ANTH-P 600', 'SEMINAR IN PREHISTORIC ARCHAEOLOGY', '14898', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SB 050', 'Ryan Kennedy', 1, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ANTH-P 600', 'SEMINAR IN PREHISTORIC ARCHAEOLOGY', '14969', 'Class Status', 'W Wednesday 9:10 AM–11:40 AM', 'SB 140', 'Stacie King', 1, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ANTH-X 371', 'UNDERGRADUATE TEACHING PRACTICUM', '6051', 'Class Status', NULL, NULL, 'Jane Goodman', 15, NULL, 'Practicum', '1–6', NULL, ARRAY[]::TEXT[], 'Students assist preparation and implementation of undergraduate courses. Interns may develop materials, oversee laboratory activities, lead discussions, maintain educational collections, or moderate online work. Students in ANTH-X 371 do not assist in grading.', ARRAY[]::TEXT[], NULL),
    ('ANTH-X 476', 'MUSEUM PRACTICUM', '7060', 'Class Status', NULL, NULL, 'Fumi Arakawa', 11, NULL, 'Practicum', '1–4', NULL, ARRAY[]::TEXT[], 'Independent work of student''s choice in one aspect of the field of museum work. Relevant readings required.', ARRAY[]::TEXT[], NULL),
    ('ANTH-X 477', 'FIELDWORK IN ANTHROPOLOGY', '7059', 'Class Status', NULL, NULL, 'Stacie King', 5, NULL, 'Practicum', '1–8', NULL, ARRAY[]::TEXT[], 'Fieldwork in anthropology carried out by the student in consultation with faculty members.', ARRAY[]::TEXT[], NULL),
    ('ANTH-X 478', 'PRACTICUM IN ANTHROPOLOGY', '7064', 'Class Status', NULL, NULL, 'Stacie King', 10, NULL, 'Independent Study', '1–8', NULL, ARRAY[]::TEXT[], 'Supervised work of an anthropological nature arranged through an outside agency or institution, such as an internship, apprenticeship, or volunteer work at a governmental office, zoo, or archaeological site. One credit hour per 45 hours or one full-time week of activity.', ARRAY[]::TEXT[], NULL),
    ('ANTH-X 479', 'FIELDWORK IN BIOANTHROPOLOGY', '15296', 'Class Status', NULL, NULL, 'Stacie King', 2, NULL, 'Independent Study', '1–8', NULL, ARRAY[]::TEXT[], 'Fieldwork involving the collection and analysis of biological or biosocial data on prehistoric and contemporary human populations. The materials or data may be paleontological, archaeological, physiological, or ecological in nature. 1 credit hour per full week of fieldwork.', ARRAY[]::TEXT[], NULL),
    ('ANTH-X 490', 'INDIVIDUAL READINGS IN ANTHROPOLOGY', '7061', 'Class Status', NULL, NULL, 'Stacie King', 50, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Independent study or research project under the guidance of an Anthropology faculty member.', ARRAY[]::TEXT[], NULL),
