    ('ARTH-A 879', 'DOCTORAL DISSERTATION', '7652', 'Class Status', NULL, NULL, 'Jeffrey Saletnik', 5, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'This variable credit course is intended for students engaged in the research for or writing of the doctoral dissertation', ARRAY[]::TEXT[], NULL),
    ('ARTH-G 901', 'ADVANCED RESEARCH', '7125', 'Class Status', NULL, NULL, 'Jeffrey Saletnik', 6, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
