    ('ASCS-Q 299', 'BUILD YOUR PROFESSIONAL STORY FOR YOUR JOB AND INTERNSHIP SEARCH', '11277', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–11:15 AM', 'EP 252', 'Michael Kendall', 16, NULL, 'Lecture', '1', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'Introduces a job and internship search paradigm focused on the developing a professional story and communicating it through resumes, cover letters, interviews, and networking. Provides training in the creation of a self-marketing plan that incorporates academic, extracurricular, and professional experiences, as well as strengths and skills into a compelling narrative.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('ASCS-Q 299', 'BUILD YOUR PROFESSIONAL STORY FOR YOUR JOB AND INTERNSHIP SEARCH', '12208', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–11:15 AM', 'EP 252', 'Michael Kendall', 14, NULL, 'Lecture', '1', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'Introduces a job and internship search paradigm focused on the developing a professional story and communicating it through resumes, cover letters, interviews, and networking. Provides training in the creation of a self-marketing plan that incorporates academic, extracurricular, and professional experiences, as well as strengths and skills into a compelling narrative.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('ASCS-X 265', 'ARTS & SCIENCES GLOBAL TECH EXPERIENCE', '14076', 'Class Status', NULL, 'WB WEB', 'Joseph Lovejoy', 135, NULL, 'Practicum', '6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Virtual experiential learning program that allows students, regardless of major and academic background, to learn technical and intercultural communication skills and apply them to real-world projects in consultation with industry leaders. Requires a learning contract, weekly journals, reflective papers, instructor meetings, and evaluation by program supervisor. Satisfactory/Fail grading.', ARRAY[]::TEXT[], NULL),
    ('ASCS-X 373', 'INTERNSHIP: THEORY INTO PRACTICE', '3250', 'Class Status', NULL, 'WB WEB', 'Madhuvanti Karyekar', 178, NULL, 'Independent Study', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides opportunity to receive academic credit for a part-time or full-time internship experience that applies classroom concepts to the world of work. Requires a learning contract, employer evaluations, weekly journal, reflective paper, and evaluation of internship site.', ARRAY[]::TEXT[], NULL),
    ('ASCS-X 375', 'FULL-TIME STATUS INTERNSHIP ASSIGNMENT', '8564', 'Class Status', NULL, 'WB WEB', 'Madhuvanti Karyekar', 29, NULL, 'Independent Study', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Offers students the opportunity to integrate academic studies with professional work experience in an internship or cooperative education assignment off-campus. Provides opportunity to receive academic credit for full-time internship experience that applies classroom concepts to the world of work. Requires a learning contract, employer evaluations, weekly journal, reflective paper, and evaluation of internship site.', ARRAY[]::TEXT[], NULL),
    ('AST-A 100', 'THE SOLAR SYSTEM', '7686', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SW 119', 'Nickolas Pingel', 0, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Celestial sphere, apparent motions of celestial objects, eclipses, history of astronomy, astronomical observations, the Earth as a planet, the Moon, the planets and their satellites, comets, meteors, theories of the origin of the solar system.', ARRAY['Transfer Indiana Initiative
