    ('AST-A 100', 'THE SOLAR SYSTEM', '11599', 'Closed', NULL, 'WB WEB', 'Shawn Slavin', 0, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Celestial sphere, apparent motions of celestial objects, eclipses, history of astronomy, astronomical observations, the Earth as a planet, the Moon, the planets and their satellites, comets, meteors, theories of the origin of the solar system.', ARRAY['Transfer Indiana Initiative
IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('AST-A 105', 'STARS AND GALAXIES', '4424', 'Closed', NULL, 'WB WEB', 'Samir Salim', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Topics include constellations, gravity, radiation, the Sun, structure and evolution of stars, neutron stars and black holes, the Milky Way galaxy, normal galaxies, active galaxies, quasars, cosmology, and the search for extraterrestrial life.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('AST-A 115', 'BIRTH AND DEATH OF THE UNIVERSE', '12035', 'Closed', 'MW Monday, Wednesday 1:55 PM–2:45 PM', 'SW 119', 'Catherine Pilachowski', 0, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Introduction to cosmology. Traces the ideas describing the origin and evolution of the universe from ancient geocentric cosmologies to the Big Bang cosmology.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('AST-A 221', 'GENERAL ASTRONOMY I', '1025', 'Class Status', 'MWF Monday, Wednesday, Friday 9:00 AM–10:10 AM', 'SE 140', 'Constantine Deliyannis', 23, NULL, 'Lecture', '4', 'SWAIN EAST', ARRAY[]::TEXT[], 'For physical science majors. Introduction to modern astronomy and astrophysics, including basic principles of mechanics, gravity, optics, radiation, and observational and experimental methods. A main theme is to explore how these principles affect the evolution of our scientific understanding of astronomical phenomena. Topics typically include the night sky, planetary bodies, the Sun and our solar system, and stars in our Milky Way galaxy.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('AST-A 305', 'MODERN OBSERVATIONAL TECHNIQUES', '29944', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SW 103', 'John Salzer', 0, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Telescopes, astronomical imaging, spectroscopic and photometric observations, and reductions.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('AST-A 515', 'EXOPLANETS AND ORBITAL DYNAMICS', '29943', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'SW 219', 'Cristobal Petrovich', 13, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'This course will provide a quantitative review of current theoretical models and observational constraints on the formation and evolution of solar and exoplanetary systems. It will also provide an in-depth introduction to basic dynamical laws and theories that can be actively applied to a wide range of astrophysical fields.', ARRAY[]::TEXT[], NULL),
    ('AST-A 780', 'SEMINAR IN ASTRONOMY', '1027', 'Class Status', 'F Friday 1:50 PM–3:30 PM', 'SW 219', 'Katherine Rhode', 9, NULL, 'Seminar', '2', 'SWAIN WEST', ARRAY[]::TEXT[], 'Selected topics of current research interest in astronomy, such as observational techniques, instrumentation, galactic and extragalactic astronomy, and cosmology.', ARRAY[]::TEXT[], NULL),
    ('AST-A 890', 'INTRODUCTION TO RESEARCH', '1028', 'Class Status', NULL, NULL, 'Enrico Vesperini', 9, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AST-A 890', 'INTRODUCTION TO RESEARCH', '1029', 'Class Status', NULL, NULL, 'Enrico Vesperini', 14, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AST-A 899', 'RESEARCH', '1030', 'Class Status', NULL, NULL, 'Enrico Vesperini', 6, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AST-A 899', 'RESEARCH', '1031', 'Class Status', NULL, NULL, 'Enrico Vesperini', 10, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('AST-G 901', 'ADVANCED RESEARCH', '1032', 'Class Status', NULL, NULL, 'Enrico Vesperini', 2, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('AST-G 901', 'ADVANCED RESEARCH', '1033', 'Class Status', NULL, NULL, 'Enrico Vesperini', 10, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('AST-S 499', 'HONORS RESEARCH', '1034', 'Class Status', NULL, NULL, 'Constantine Deliyannis', 7, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'Students will carry out astronomical research closely supervised by faculty member in the department. Students will write a research report and given an oral presentation during the second semester of their senior year.', ARRAY[]::TEXT[], NULL),
    ('AST-X 299', 'EXPLORATORY RESEARCH IN ASTRONOMY AND ASTROPHYSICS', '7871', 'Class Status', NULL, NULL, 'Constantine Deliyannis', 10, NULL, 'Research', '1', NULL, ARRAY[]::TEXT[], 'Introductory research in astronomy, closely supervised by a faculty member. Research topics may include observational, experimental, computational, or theoretical applications.', ARRAY[]::TEXT[], NULL),
    ('AST-X 299', 'EXPLORATORY RESEARCH IN ASTRONOMY AND ASTROPHYSICS', '7872', 'Class Status', NULL, NULL, 'Constantine Deliyannis', 10, NULL, 'Research', '1', NULL, ARRAY[]::TEXT[], 'Introductory research in astronomy, closely supervised by a faculty member. Research topics may include observational, experimental, computational, or theoretical applications.', ARRAY[]::TEXT[], NULL),
    ('AST-X 390', 'READING COURSE', '1026', 'Class Status', NULL, NULL, 'Constantine Deliyannis', 9, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Individualized readings in astronomy and astrophysics.', ARRAY[]::TEXT[], NULL),
    ('AST-X 399', 'RESEARCH IN ASTRONOMY AND ASTROPHYSICS', '6732', 'Class Status', NULL, NULL, 'Constantine Deliyannis', 8, NULL, 'Research', '1–6', NULL, ARRAY[]::TEXT[], 'Research in astronomy, closely supervised by a faculty member. Projects can be theoretical, experimental, or observational, and may include opportunities to train in the planning and execution of data gathering runs at research telescopes and facilities, and in data mining.', ARRAY[]::TEXT[], NULL),
    ('BIOC-B 511', 'DUPLICATING AND EXPRESSING THE GENOME', '12949', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SI 001', 'Matt Bochman', 8, NULL, 'Lecture', '3', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Examines genomic structure, DNA topology and replication mechanisms in the context of cell function for all three domains of life. Studies the pathological consequences of failure to duplicate and maintain the genome. An analysis of classic and current primary literature will be a major component.', ARRAY[]::TEXT[], NULL),
    ('BIOC-B 522', 'STRUCTURAL BIOLOGY OF SUPRAMOLECULAR COMPLEXES', '8696', 'Closed', 'MW Monday, Wednesday 10:20 AM–11:35 AM', 'SI 001', 'Adam Zlotnick', 0, NULL, 'Lecture', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Students will participate in a detailed look at selected supramolecular complexes from the perspective of structural biology. An emphasis will be placed on application of molecular graphics to understand function and intermolecular interactions.', ARRAY[]::TEXT[], NULL),
    ('BIOC-B 530', 'MACROMOLECULAR STRUCTURE AND FUNCTION', '5950', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SI 001', 'Marc Morais', 17, NULL, 'Lecture', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Molecular Biology and Physical Chemistry Review; Recombinant DNA Techniques; Heterologous Protein Expression Systems; Description and Measurement of Stabilizing Forces in Macromolecular Structure; Protein Secondary, Tertiary and Quaternary Structures: Circular Dichroism and Analytical Ultracentrifugation; Nucleic and Structure and Probing; Protein Structure Determination by Nuclear Magnetic Resonance (NMR); Protein Structure Determination by X-ray Crystallography; Building and Refinement of a Protein Structure from Crystallographic Data.', ARRAY[]::TEXT[], NULL),
    ('BIOC-B 531', 'BIOMOLECULAR ANALYSIS AND INTERACTION', '5951', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SI 001', 'Adam Zlotnick', 20, NULL, 'Lecture', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Ligand Binding Models: Single Site Binding and Multiple and Competitive Site Binding; and Determination and Measurement of Binding Interactions and Antibody-based Interaction Methods.', ARRAY[]::TEXT[], NULL),
    ('BIOC-B 580', 'INTRODUCTION TO BIOCHEMICAL RESEARCH', '1035', 'Class Status', NULL, NULL, 'Matt Bochman, Celeste Nicola', 15, NULL, 'Laboratory', '3', NULL, ARRAY[]::TEXT[], 'Objectives and techniques of biochemical research.', ARRAY[]::TEXT[], NULL),
    ('BIOC-B 600', 'SEMINAR IN BIOCHEMISTRY', '1036', 'Class Status', 'W Wednesday 4:40 PM–5:40 PM', 'SI 001', 'Staff', 23, NULL, 'Seminar', '1', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Advanced critical analysis of the current scientific literature and scientific presentations. Attendance and participation in the weekly Biochemistry Program seminar series is required.', ARRAY[]::TEXT[], NULL),
    ('BIOC-B 680', 'SPECIAL TOPICS IN BIOCHEMISTRY', '3149', 'Class Status', 'Th Thursday 3:00 PM–6:00 PM', 'SI 001', 'Adam Zlotnick, Roger Innes', 10, NULL, 'Lecture', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Topics vary yearly and include the following: physico-chemical techniques in the study of macromolecules; experimental methods in enzymology; organic chemistry of enzymatic reactions and enzyme models; conformational properties and macromolecules.', ARRAY[]::TEXT[], NULL),
    ('BIOC-B 680', 'SPECIAL TOPICS IN BIOCHEMISTRY', '15080', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'JH A107', 'Sidney Shaw', 3, NULL, 'Lecture', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Topics vary yearly and include the following: physico-chemical techniques in the study of macromolecules; experimental methods in enzymology; organic chemistry of enzymatic reactions and enzyme models; conformational properties and macromolecules.', ARRAY[]::TEXT[], NULL),
