    ('BIOC-G 599', 'THESIS RESEARCH', '3647', 'Class Status', NULL, NULL, 'James Drummond', 20, NULL, 'Lecture', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('BIOC-G 901', 'ADVANCED RESEARCH', '3403', 'Class Status', NULL, NULL, 'Celeste Nicola, Matt Bochman', 33, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('BIOL-B 221', 'THE BIOLOGY OF COFFEE: BOTANY, PHYSIOLOGY, AND SUSTAINABILITY', '13581', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'JH 065', 'David Kehoe', 0, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Addresses three intertwined aspects of the biology of coffee: the botany of coffee plants and coffee beans, the human physiological response to coffee and caffeine, and the biological sustainability issues surrounding the growth of coffee plants and the production of coffee.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('BIOL-B 370', 'PLANTS AND HUMAN AFFAIRS IN THE GENOME ENGINEERING ERA', '14472', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 227', 'Lachezar Nikolov', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Provides a survey of plants and plant products used by humans. Covers molecular aspects of plant improvement for food, biofuels, and medicines using novel technologies, such as CRISPR, transgenesis, and synthetic biology in the face of global environmental change.', ARRAY[]::TEXT[], NULL),
    ('BIOL-G 599', 'THESIS RESEARCH', '3064', 'Class Status', NULL, NULL, 'Armin Moczek', 5, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('BIOL-G 901', 'ADVANCED RESEARCH', '1038', 'Class Status', NULL, NULL, 'Armin Moczek', 47, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('BIOL-H 122', 'HONORS INTRODUCTORY BIOLOGY', '14512', 'Class Status', 'Tu Tuesday 11:10 AM–12:10 PM', 'JH 015 JH 015', 'Sidney Shaw', 7, NULL, 'Laboratory', '4', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Provides an in-depth overview of the genome and the eukaryotic cell to prepare advanced undergraduates for majors in the life sciences. Covers classical, molecular, and epi-genetic content together with an integrated view of cellular organelles and systems.', ARRAY[]::TEXT[], NULL),
